UPDATE personas AS persona
SET
  current_version_id = seed.version_id,
  updated_at = NOW()
FROM (
  VALUES
    ('persona.ai-content-creator', '71000000-0000-4000-8000-000000000001'::uuid),
    ('persona.crm-builder', '71000000-0000-4000-8000-000000000002'::uuid),
    ('persona.instagram-automator', '71000000-0000-4000-8000-000000000003'::uuid),
    ('persona.meal-planner', '71000000-0000-4000-8000-000000000004'::uuid),
    ('persona.web-builder', '71000000-0000-4000-8000-000000000005'::uuid)
) AS seed(persona_id, version_id)
WHERE persona.persona_id = seed.persona_id
  AND persona.current_version_id IS DISTINCT FROM seed.version_id;

