-- ============================================
-- Canonical Atoms（E2E + dev 共通の最小保証データ）
-- seed-canonical.sql と同一の 3 atom を ON CONFLICT で冪等に追加。
-- supabase db reset でも /lessons に最低 3 件が表示されることを保証する。
-- ============================================
ON CONFLICT (atom_id) DO UPDATE SET source_path = EXCLUDED.source_path, updated_at = now();

    'atom.canonical.ai-tool-intro',
    'reviewed',
    jsonb_build_object(
      'id', 'atom.canonical.ai-tool-intro',
      'title', 'AIツールの選び方入門',
      'summary', '学習を進めるうえで役立つAIツールを目的別に整理します。',
      'persona_tags', jsonb_build_array('ai-first-learner'),
      'goal_tags', jsonb_build_array('understand-ai-tools'),
      'status', 'reviewed'
    ),
    '# AIツールの選び方入門' || E'\n\n' || '学習を進めるうえで役立つAIツールを目的別に整理します。',
    '{}'::jsonb
  ),
  (
    'atom.canonical.ai-coding-basics',
    'reviewed',
    jsonb_build_object(
      'id', 'atom.canonical.ai-coding-basics',
      'title', 'AIコーディングの基礎',
      'summary', 'AIアシスタントと一緒に書く基本の流れを体験します。',
      'persona_tags', jsonb_build_array('ai-first-learner'),
      'goal_tags', jsonb_build_array('learn-ai-coding'),
      'status', 'reviewed'
    ),
    '# AIコーディングの基礎' || E'\n\n' || 'AIアシスタントと一緒に書く基本の流れを体験します。',
    '{}'::jsonb
  ),
  (
    'atom.canonical.ai-workflow-design',
    'reviewed',
    jsonb_build_object(
      'id', 'atom.canonical.ai-workflow-design',
      'title', 'AI業務ワークフローの設計',
      'summary', '業務プロセスにAIを組み込むための最小構成を学びます。',
      'persona_tags', jsonb_build_array('ai-first-learner'),
      'goal_tags', jsonb_build_array('design-ai-workflow'),
      'status', 'reviewed'
    ),
    '# AI業務ワークフローの設計' || E'\n\n' || '業務プロセスにAIを組み込むための最小構成を学びます。',
    '{}'::jsonb
  );

-- Wire each canonical atom's current_version_id
UPDATE lesson_atoms la
   SET current_version_id = v.version_id,
       updated_at = now()
  FROM (
    SELECT DISTINCT ON (atom_id) atom_id, version_id
      FROM lesson_atom_versions
     WHERE atom_id IN (
       'atom.canonical.ai-tool-intro',
       'atom.canonical.ai-coding-basics',
       'atom.canonical.ai-workflow-design'
     )
     ORDER BY atom_id, imported_at DESC
  ) v
 WHERE la.atom_id = v.atom_id;


-- ============================================
-- テスト用ユーザー（ローカル開発環境用）
-- supabase db reset 時に自動作成される
-- ============================================
DO $$
DECLARE
  demo_id uuid;
  user_exists boolean;
BEGIN
  -- デモユーザーの存在チェック（冪等性確保）
  SELECT EXISTS(SELECT 1 FROM auth.users WHERE email = 'demo@school.app') INTO user_exists;

  IF NOT user_exists THEN
      instance_id,
      id,
      aud,
      role,
      email,
      encrypted_password,
      email_confirmed_at,
      raw_user_meta_data,
      created_at,
      updated_at,
      confirmation_token,
      email_change_token_new,
      recovery_token,
      email_change_token_current,
      email_change,
      phone_change,
      phone_change_token,
      reauthentication_token,
      is_sso_user,
      is_anonymous
    ) VALUES (
      '00000000-0000-0000-0000-000000000000',
      gen_random_uuid(),
      'authenticated',
      'authenticated',
      'demo@school.app',
      crypt('Demo123456!', gen_salt('bf')),
      now(),
      '{"display_name": "デモユーザー"}'::jsonb,
      now(),
      now(),
      '', '', '', '', '', '', '', '',
      false,
      false
    ) RETURNING id INTO demo_id;

    RAISE NOTICE 'Demo user created with id: %', demo_id;
  ELSE
    SELECT id INTO demo_id FROM auth.users WHERE email = 'demo@school.app';
    RAISE NOTICE 'Demo user already exists with id: %', demo_id;
  END IF;

  RAISE NOTICE '';
  RAISE NOTICE '==========================================';
  RAISE NOTICE 'AI School seed data inserted successfully!';
  RAISE NOTICE '==========================================';
  RAISE NOTICE 'Demo user credentials:';
  RAISE NOTICE '  Email:    demo@school.app';
  RAISE NOTICE '  Password: Demo123456!';
  RAISE NOTICE '==========================================';
END $$;
